import{_ as a,o as i,c as n,ag as l}from"./chunks/framework.hRhVUe7m.js";const k=JSON.parse('{"title":"预配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pre-config.md","filePath":"guide/pre-config.md"}'),e={name:"guide/pre-config.md"};function p(t,s,c,o,d,r){return i(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="预配置" tabindex="-1">预配置 <a class="header-anchor" href="#预配置" aria-label="Permalink to &quot;预配置&quot;">​</a></h1><div class="lead-panel"><span class="kicker">首次启动之前</span><h1>先把工作区、配置文件和通道范围对齐</h1><p>MathClaw 更像一套持续运行的产品，而不是一个单独脚本。只要 workspace、配置路径和通道凭据指向同一个环境，首次启动就会顺得多。</p><div class="badge-list"><span>workspace</span><span>配置文件</span><span>模型</span><span>通道</span></div></div><div class="stat-strip"><div class="stat-chip"><strong>1</strong><span>统一 workspace，保存会话、记忆、图谱和定时任务状态。</span></div><div class="stat-chip"><strong>1</strong><span>主配置路径使用 <code>~/.mathclaw/config.json</code>。</span></div><div class="stat-chip"><strong>3</strong><span>关键检查项：路径可写、模型可用、通道凭据有效。</span></div></div><h2 id="运行时基线" tabindex="-1">运行时基线 <a class="header-anchor" href="#运行时基线" aria-label="Permalink to &quot;运行时基线&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>workspace 结构</h3><p>共享工作区让所有管理页面都能读到同一份学习历史。</p><ul><li>原始会话日志。</li><li>日记忆与周记忆快照。</li><li>知识图谱与错题图谱 JSON。</li><li>心跳所需的 cron 状态。</li></ul></div><div class="doc-card"><h3>配置解析</h3><p>控制台默认读取标准用户配置目录，同时保持跨机器可移植。</p><ul><li>主路径：<code>~/.mathclaw/config.json</code>。</li><li>从 <code>console/</code> 启动时可显式传入 workspace。</li><li>优先使用仓库相对路径，而不是机器专属绝对路径。</li></ul></div></div><p>典型 workspace 结构：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>workspace/</span></span>
<span class="line"><span>  sessions/</span></span>
<span class="line"><span>  memory/</span></span>
<span class="line"><span>    daily_conversations/</span></span>
<span class="line"><span>    daily_memory/</span></span>
<span class="line"><span>    weekly_memory/</span></span>
<span class="line"><span>    graphs/</span></span>
<span class="line"><span>  cron/</span></span></code></pre></div><p>从仓库内启动控制台时，建议显式传入 workspace：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> console</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MATHCLAW_CONSOLE_WORKSPACE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">../workspace</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve.py</span></span></code></pre></div><h2 id="首次启动检查清单" tabindex="-1">首次启动检查清单 <a class="header-anchor" href="#首次启动检查清单" aria-label="Permalink to &quot;首次启动检查清单&quot;">​</a></h2><div class="checklist-grid"><div class="checklist-card"><h3>模型层</h3><ul><li>确认主模型和 provider 可连通。</li><li>确认 API Key 已加载到预期配置源。</li><li>如果要解析 PDF / 图片，确认附件解析模型也可用。</li></ul></div><div class="checklist-card"><h3>通道层</h3><ul><li>只启用真正需要暴露的通道。</li><li>先检查凭据，再启动 gateway。</li><li>即使外部通道开启，也建议保留 console 作为管理入口。</li></ul></div></div><h2 id="启动后优先检查的页面" tabindex="-1">启动后优先检查的页面 <a class="header-anchor" href="#启动后优先检查的页面" aria-label="Permalink to &quot;启动后优先检查的页面&quot;">​</a></h2><div class="callout-strip"><div class="callout-chip"><strong>运行状态</strong> 确认 gateway、console、provider 和通道是否健康。 </div><div class="callout-chip"><strong>心跳</strong> 查看日总结、周总结和定时任务是否仍在正常执行。 </div><div class="callout-chip"><strong>图谱与 Skills</strong> 确认记忆页和附件输出 Skill 是否按预期工作。 </div></div>`,13)])])}const g=a(e,[["render",p]]);export{k as __pageData,g as default};
